"""Firmware version detection and management"""

import json
import logging
import os
import re
from datetime import datetime
from pathlib import Path

from . import parser

log = logging.getLogger(__name__)

# Version compatibility file location
FIRMWARE_VERSIONS_FILE = "/usr/local/share/att-gateway-check/firmware_versions.json"

# Fallback for development
if not os.path.exists(FIRMWARE_VERSIONS_FILE):
    # Try relative to module
    module_dir = Path(__file__).parent.parent.parent.parent.parent.parent
    FIRMWARE_VERSIONS_FILE = module_dir / "usr/local/share/att-gateway-check/firmware_versions.json"


def load_version_registry():
    """Load the firmware version compatibility registry.

    Returns:
        Dictionary with version information
    """
    try:
        with open(FIRMWARE_VERSIONS_FILE, 'r') as f:
            return json.load(f)
    except FileNotFoundError:
        log.warning(f"Firmware versions file not found: {FIRMWARE_VERSIONS_FILE}")
        return {"supported_versions": [], "breaking_changes": []}
    except json.JSONDecodeError as e:
        log.error(f"Failed to parse firmware versions file: {e}")
        return {"supported_versions": [], "breaking_changes": []}


def detect_firmware_version(gateway_client):
    """Detect firmware version from the gateway.

    Args:
        gateway_client: Authenticated gateway client with session

    Returns:
        Version string (e.g., "6.34.7"), or None if detection fails
    """
    try:
        # Fetch the sysinfo page
        response = gateway_client.session.get(
            f"{gateway_client.base}/cgi-bin/sysinfo.ha",
            timeout=10
        )

        if response.status_code != 200:
            log.warning(f"sysinfo.ha returned status {response.status_code}")
            return None

        # Extract version using parser
        version = parser.extract_firmware_version(response.text)

        if version:
            log.info(f"Detected firmware version: {version}")
            return version
        else:
            log.warning("Could not extract firmware version from sysinfo.ha")
            return None

    except Exception as e:
        log.error(f"Error detecting firmware version: {e}")
        return None


def match_version_to_handler(version):
    """Match a firmware version to its handler class name.

    Args:
        version: Version string (e.g., "6.34.7")

    Returns:
        Tuple of (handler_name, version_info_dict) or (None, None) if no match
    """
    if not version:
        return None, None

    registry = load_version_registry()

    for version_info in registry.get("supported_versions", []):
        pattern = version_info.get("version_pattern")
        if pattern and re.match(pattern, version):
            handler = version_info.get("handler")
            log.info(f"Matched version {version} to handler {handler}")
            return handler, version_info

    log.warning(f"No handler found for version {version}")
    return None, None


def get_handler_class(version):
    """Get the appropriate firmware handler class for a version.

    Args:
        version: Version string (e.g., "6.34.7")

    Returns:
        Handler class, or FirmwareHandlerDefault if no match
    """
    from . import handlers

    handler_name, version_info = match_version_to_handler(version)

    if handler_name == "FirmwareHandler_6_34":
        return handlers.FirmwareHandler_6_34
    # Add more version handlers here as they're created
    else:
        log.warning(f"Using default handler for unknown version: {version}")
        return handlers.FirmwareHandlerDefault


def load_cached_version(cache_file="/var/lib/att_gateway/gateway_info.json"):
    """Load cached gateway information including firmware version.

    Args:
        cache_file: Path to cache file

    Returns:
        Dictionary with cached info, or empty dict if not found
    """
    try:
        if os.path.exists(cache_file):
            with open(cache_file, 'r') as f:
                return json.load(f)
    except Exception as e:
        log.debug(f"Could not load cached version: {e}")

    return {}


def save_cached_version(version, cache_file="/var/lib/att_gateway/gateway_info.json"):
    """Save gateway information to cache.

    Args:
        version: Firmware version string
        cache_file: Path to cache file
    """
    try:
        # Ensure directory exists
        os.makedirs(os.path.dirname(cache_file), exist_ok=True)

        cache_data = {
            "firmware_version": version,
            "detected_at": datetime.now().isoformat(),
        }

        with open(cache_file, 'w') as f:
            json.dump(cache_data, f, indent=2)

        log.debug(f"Saved firmware version to cache: {version}")

    except Exception as e:
        log.warning(f"Could not save cached version: {e}")


def check_version_change(current_version, cache_file="/var/lib/att_gateway/gateway_info.json"):
    """Check if firmware version has changed since last run.

    Args:
        current_version: Currently detected version
        cache_file: Path to cache file

    Returns:
        Tuple of (changed: bool, previous_version: str or None)
    """
    cached = load_cached_version(cache_file)
    previous_version = cached.get("firmware_version")

    if not previous_version:
        # First run, no previous version
        return False, None

    if previous_version != current_version:
        log.warning("=" * 60)
        log.warning("FIRMWARE VERSION CHANGED!")
        log.warning(f"Old: {previous_version}")
        log.warning(f"New: {current_version}")
        log.warning("AT&T updated your gateway firmware.")
        log.warning("Monitoring for configuration changes...")
        log.warning("=" * 60)
        return True, previous_version

    return False, previous_version


def warn_unknown_version(version):
    """Log a warning for an unknown/untested firmware version.

    Args:
        version: The unknown version string
    """
    log.warning("=" * 60)
    log.warning(f"UNSUPPORTED FIRMWARE VERSION: {version}")
    log.warning("")
    log.warning("This version has not been tested.")
    log.warning("AT&T may have changed the interface.")
    log.warning("")
    log.warning("Please report this version at:")
    log.warning("https://github.com/yourusername/att-gateway-check/issues")
    log.warning("")
    log.warning("Attempting to use default handler...")
    log.warning("=" * 60)
